      "detail": "The full detailed engineering brief — 10-20 sentences with every file path, function name, prop name, and exact change described"
    }
  ]
}

RULES FOR SUGGESTIONS:

Produce exactly 2-3 suggestions. Each suggestion has a "preview" (1 sentence, ~15 words) and a "detail" (full engineering brief).

The "detail" field is what gets sent to the coding pipeline. The pipeline has a 128K context coder that handles 6-8 files per task. Each suggestion's detail should generate 2-4 large tasks.

Suggestion categories (pick 2-3 that apply):
1. CRITICAL FIXES: All bugs, broken imports, wrong props, missing wiring. For EACH broken file: state the path, what's wrong, and the exact fix. Include variable names, prop names, function signatures.
2. MISSING FEATURES: Core functionality that was requested but not implemented. Describe each feature in detail — what component renders it, what state it needs, what hooks/handlers to add, what files to create.
3. UI/UX POLISH & ENHANCEMENTS: Animations, responsive design, accessibility, visual improvements, error states, loading states. Reference specific CSS classes, component names, and design patterns.

Each "detail" should be a DENSE paragraph of 10-20 sentences. It should read like a complete engineering brief — a developer can execute every change from the description alone. Reference specific file paths, function names, prop names, state variables, and CSS classes throughout.

If the project is in great shape (90+), focus suggestions on enhancements: new features, dark mode, localStorage persistence, accessibility, performance optimization.`;

return [{
  json: {
    model: $env.FINAL_REVIEWER_MODEL || 'mistralai/magistral-small-2509',
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.5,
    top_p: 0.75,
    max_tokens: 16384
  }
}];

// Parse final review — robust JSON extraction
const msg = ($json.choices && $json.choices[0] && $json.choices[0].message) || {};
let raw = msg.content || '';

// If content is empty/whitespace, try reasoning_content
if (!raw.trim()) raw = msg.reasoning_content || '';

// Strip thinking blocks
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();

// Strip markdown code fences
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

// Try multiple parse strategies
let review;
try {
  // Strategy 1: direct parse (content is pure JSON)
  review = JSON.parse(content);
} catch(e1) {
  try {
    // Strategy 2: extract JSON object with balanced braces
    let depth = 0, start = -1, end = -1;
    for (let i = 0; i < content.length; i++) {
      if (content[i] === '{') { if (depth === 0) start = i; depth++; }
      if (content[i] === '}') { depth--; if (depth === 0) { end = i + 1; break; } }
    }
    if (start >= 0 && end > start) {
      review = JSON.parse(content.substring(start, end));
    } else {
      throw new Error('No balanced JSON found');
    }
  } catch(e2) {
    review = { final_quality: 0, summary: 'Final review parse failed: ' + e2.message, suggestions: [] };
  }
}

// Normalize suggestions format (handle both string[] and {preview, detail}[] )
if (review.suggestions) {
  review.suggestions = review.suggestions.map(s => {
    if (typeof s === 'string') return s;
    if (s && s.preview) return s;
    return String(s);
  });
}

const staticData = $getWorkflowStaticData('global');
staticData._finalReview = review;

// Send callback to Forge
try {
  const http = require('http');
  const projectId = $('Prepare Planner Input').first().json.project_id || 'unknown';
  const cbBody = JSON.stringify({
    event: 'final_review_complete',
    project_id: projectId,
    data: { quality: review.final_quality, summary: review.summary, suggestions: review.suggestions }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  req.on('error', () => {});
  req.write(cbBody);
  req.end();
} catch(e) {}

return [{ json: review }];

const http = require('http');
function lmsRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const lmsHost = ($env.LM_STUDIO_HOST || 'http://10.0.0.100:1234').replace(/^https?:\/\//, '');
    const [hostname, portStr] = lmsHost.split(':');
    const bodyStr = body ? JSON.stringify(body) : null;
    const req = http.request({
      hostname, port: parseInt(portStr) || 1234, path, method,
      headers: {
        Authorization: 'Bearer ' + ($env.LLM_API_KEY || ''),
        'Content-Type': 'application/json',
        ...(bodyStr ? { 'Content-Length': Buffer.byteLength(bodyStr) } : {})
      }
    }, res => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({}); } });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}
const modelKey = $env.FINAL_REVIEWER_MODEL || '';
try {
  const resp = await lmsRequest('GET', '/api/v1/models');
  for (const m of (resp.models || [])) {
    if (m.key === modelKey) {
      for (const inst of (m.loaded_instances || [])) {
        try { await lmsRequest('POST', '/api/v1/models/unload', { instance_id: inst.id }); } catch(e) {}
      }
    }
  }
} catch(e) {}
return [{ json: $('Final: Review Parse').first().json }];

// Status callback to Forge — fire and forget
const http = require('http');
const staticData = $getWorkflowStaticData('global');
const projectId = staticData._currentProjectId || $('Prepare Planner Input').first().json.project_id || 'unknown';
const fixResults = staticData._fixResults || [];

try {
  const body = JSON.stringify({
    event: 'fix_applied',
    project_id: projectId,
    data: { files_fixed: fixResults, fix_count: fixResults.length }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
  });
  req.on('error', () => {});
  req.write(body);
  req.end();
} catch(e) {}

return [$input.all()[0]];

// Research: Fetch library docs from Context7 MCP
// Uses require('http') with Accept header (required by Streamable HTTP MCP protocol)
const http = require('http');
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];
const tasks = $json.tasks || [];

// 1. Extract libraries
const libs = new Set();
const pkgFile = allFiles.find(f => f.path === 'package.json');
if (pkgFile) {
  try {
    const pkg = JSON.parse(pkgFile.content);
    for (const dep of Object.keys(pkg.dependencies || {})) libs.add(dep);
    for (const dep of Object.keys(pkg.devDependencies || {})) libs.add(dep);
  } catch(e) {}
}
const taskText = tasks.map(t => t.description || '').join(' ').toLowerCase();
const knownLibs = ['react', 'next', 'nextjs', 'vite', 'tailwindcss', 'tailwind', 'express', 'prisma', 'framer-motion', 'heroui', 'zustand', 'zod', 'three', 'react-three', 'r3f', 'drei', '@react-three/fiber', '@react-three/drei'];
for (const lib of knownLibs) {
  if (taskText.includes(lib)) {
      const mapped = {'nextjs':'next','tailwind':'tailwindcss','react-three':'@react-three/fiber','r3f':'@react-three/fiber','drei':'@react-three/drei'};
      libs.add(mapped[lib] || lib);
    }
}
if (allFiles.some(f => f.path.match(/\.(jsx|tsx)$/))) libs.add('react');
// No hardcoded priority — fetch docs for whatever the project actually uses
// Skip trivial/internal packages that don't have useful docs
const skipList = new Set(['autoprefixer', 'postcss', 'typescript', 'vite', '@vitejs/plugin-react', '@types/react', '@types/node', '@types/react-dom', 'eslint', 'prettier']);
const toFetch = [...libs].filter(l => !skipList.has(l)).slice(0, 7);

if (toFetch.length === 0) {
  staticData._researchDocs = '';
  return [{ json: $json }];
}

// 2. MCP HTTP helper
function mcpRequest(sessionId, method, params) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({ jsonrpc: '2.0', method, params, id: Date.now() });
    const req = http.request({
      hostname: 'docky', port: 8811, path: '/mcp', method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json, text/event-stream',
        'Content-Length': Buffer.byteLength(body),
        ...(sessionId ? { 'Mcp-Session-Id': sessionId } : {})
      }
    }, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => resolve({ data, sessionId: res.headers['mcp-session-id'] }));
    });
    req.on('error', reject);
    req.setTimeout(20000, () => { req.destroy(); reject(new Error('timeout')); });
    req.write(body);
    req.end();
  });
}

function parseSSE(raw) {
  for (const line of raw.split('\n')) {
    if (line.startsWith('data: ')) {
      try { return JSON.parse(line.slice(6)); } catch(e) {}
    }
  }
  return {};
}

const docs = [];
const errors = [];

try {
  // Initialize session
  const init = await mcpRequest(null, 'initialize', {
    protocolVersion: '2024-11-05', capabilities: {},
    clientInfo: { name: 'eek-go-research', version: '1.0' }
  });
  const sid = init.sessionId;
  if (!sid) throw new Error('No MCP session ID');

  for (const lib of toFetch) {
    try {
      // Resolve library ID
      const resolve = await mcpRequest(sid, 'tools/call', {
        name: 'resolve-library-id', arguments: { libraryName: lib }
      });
      const resolveData = parseSSE(resolve.data);
      const resolveText = (resolveData.result?.content || []).map(c => c.text || '').join('');
      const idMatch = resolveText.match(/Context7-compatible library ID:\s*(\/[\w.-]+\/[\w.-]+)/);
      if (!idMatch) { errors.push(lib + ': no ID'); continue; }

      // Get docs
      const docsResp = await mcpRequest(sid, 'tools/call', {
        name: 'get-library-docs',
        arguments: { context7CompatibleLibraryID: idMatch[1], tokens: 5000, topic: 'setup components hooks API examples' }
      });
      const docsData = parseSSE(docsResp.data);
      const docText = (docsData.result?.content || []).map(c => c.text || '').join('');
      if (docText.length > 100) {
        docs.push('## ' + lib + ' (' + idMatch[1] + ')\n' + docText.substring(0, 8000));
      }
    } catch(e) { errors.push(lib + ': ' + e.message); }
  }
} catch(e) {
  errors.push('init: ' + e.message);
}

// Prepend a universal design guide
const designGuide = `## UI/UX Design Principles for Web Applications

### Layout
- Main interaction element must be centered and visually dominant (40-60% of viewport)
- Use vertical single-column layouts for game/app UIs — never side-by-side grids unless it's a dashboard
- Content hierarchy: hero/main action → stats/feedback → secondary actions (shop, settings)
- Mobile-first: everything should work on a 375px wide screen and scale up
- Scrollable secondary content (shops, lists) should never push the main interaction off-screen

### Visual Feedback
- Every user interaction (click, purchase, hover) MUST produce visible feedback
- Number changes should animate (bounce, scale pulse, color flash)
- Buttons: press animation (scale 0.95), hover glow/lift, disabled state with reduced opacity
- Success actions: green flash, checkmark, particle burst
- Use CSS transitions (200-300ms) on all interactive elements

### Color & Contrast
- Dark backgrounds with bright accent colors for maximum contrast
- Use gradients over flat colors for depth (e.g., purple-900 to indigo-950)
- Interactive elements should be the brightest items on screen
- Affordability: green = can buy, red/gray = locked, gold = premium
- Text must have sufficient contrast — white/yellow on dark, with text-shadow for readability

### Typography
- Big, bold numbers for scores/stats (text-4xl to text-6xl)
- Clear hierarchy: title (bold, large) → subtitle (medium) → body (regular, smaller)
- Use font-weight differences, not just size, to create hierarchy
- Monospace or tabular numbers for counters that change frequently

### Animation
- Idle animations (slow pulse, float, rotate) make the UI feel alive
- Click animations should be fast (100-200ms) and snappy
- Spawn/death animations for appearing/disappearing elements (scale 0→1, fade in/out)
- Use CSS will-change on animated elements for performance
- Stagger animations for lists (each item slightly delayed)

### Cards & Containers
- Rounded corners (border-radius: 12-16px)
- Subtle shadows for depth (shadow-lg, shadow-xl)
- Semi-transparent backgrounds with backdrop-blur for overlay panels
- Hover: lift (translateY -2 to -4px) + shadow increase
- Border: subtle (1px border with low-opacity white or accent color)`;

// 3. Fetch UI component inspiration from Magic MCP (21st.dev)
let magicDocs = '';
try {
  // Extract UI-related keywords from task descriptions for search
  const uiKeywords = [];
  const taskDescs = tasks.map(t => (t.description || '').toLowerCase()).join(' ');
  const uiPatterns = ['button', 'card', 'shop', 'form', 'input', 'modal', 'dialog', 'nav', 'header', 'footer', 'sidebar', 'menu', 'table', 'list', 'grid', 'dashboard', 'counter', 'score', 'game', 'animation', 'toggle', 'dropdown'];
  for (const p of uiPatterns) {
    if (taskDescs.includes(p)) uiKeywords.push(p);
  }

  if (uiKeywords.length > 0) {
    // Reuse the existing MCP session or create new one for magic
    const magicInit = await new Promise((resolve, reject) => {
      const body = JSON.stringify({ jsonrpc: '2.0', method: 'initialize', params: { protocolVersion: '2024-11-05', capabilities: {}, clientInfo: { name: 'eek-go-magic', version: '1.0' } }, id: Date.now() });
      const req = http.request({
        hostname: 'docky', port: 8811, path: '/mcp', method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream', 'Content-Length': Buffer.byteLength(body) }
      }, res => {
        let data = ''; res.on('data', c => data += c);
        res.on('end', () => resolve({ data, sessionId: res.headers['mcp-session-id'] }));
      });
      req.on('error', reject);
      req.setTimeout(10000, () => { req.destroy(); reject(new Error('timeout')); });
      req.write(body); req.end();
    });

    const magicSid = magicInit.sessionId;
    if (magicSid) {
      // Search for 2-3 relevant component types
      const searchTerms = uiKeywords.slice(0, 3).map(k => k + ' component');
      for (const query of searchTerms) {
        try {
          const inspResp = await mcpRequest(magicSid, 'tools/call', {
            name: '21st_magic_component_inspiration',
            arguments: { message: 'I need a modern ' + query + ' for a web app', searchQuery: query }
          });
          const inspData = parseSSE(inspResp.data);
          const inspText = (inspData.result?.content || []).map(c => c.text || '').join('');
          if (inspText.length > 200) {
            // Extract just the code examples, not the full JSON
            try {
              const components = JSON.parse(inspText);
              if (Array.isArray(components)) {
                const examples = components.slice(0, 2).map(c => {
                  const code = c.demoCode || c.code || '';
                  const name = c.demoName || c.name || query;
                  return '### ' + name + '\n```tsx\n' + code + '\n```';
                }).join('\n\n');
                if (examples.length > 100) {
                  magicDocs += '\n\n## Magic UI: ' + query + '\n' + examples;
                }
              }
            } catch(e) {
              // Not JSON, use raw text (truncated)
              if (inspText.length > 100) {
                magicDocs += '\n\n## Magic UI: ' + query + '\n' + inspText.substring(0, 4000);
              }
            }
          }
        } catch(e) { /* skip this query */ }
      }
    }
  }
} catch(e) {
  // Magic MCP down — continue without it
}

if (magicDocs) {
  docs.push('## UI Component Examples (from 21st.dev Magic)\n' + magicDocs);
}

staticData._researchDocs = docs.length > 0
  ? designGuide + '\n\n---\n\n## Library Documentation (from Context7)\n\n' + docs.join('\n\n---\n\n')
  : designGuide;

// Callback
try {
  const projectId = $('Extract Input').first().json.project_id || staticData._currentProjectId || 'unknown';
  const cbBody = JSON.stringify({
    event: 'research_complete', project_id: projectId,
    data: { libraries_fetched: toFetch, doc_count: docs.length, doc_chars: docs.reduce((s,d) => s+d.length, 0), errors: errors.length ? errors : undefined }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  req.on('error', () => {});
  req.write(cbBody);
  req.end();
} catch(e) {}

return [{ json: $json }];

