import React from 'react'
import GameUI from './components/GameUI'

function App() {
  return <GameUI />
}

export default App

import { create } from 'zustand'
import { persist, type PersistStorage } from 'zustand/middleware'

interface GameState {
  poop: number
  clickPower: number
  autoRate: number
  unlockedUpgrades: Set<string>
  gameStarted: boolean
}

interface GameActions {
  incrementPoop: () => void
  setClickPower: (power: number) => void
  setAutoRate: (rate: number) => void
  unlockUpgrade: (upgradeId: string) => void
  resetGame: () => void
}

type GameStateStore = GameState & GameActions

const localStorage: PersistStorage<GameState> = {
  getItem: (key) => {
    const item = window.localStorage.getItem(key)
    if (!item) return null

    try {
      const parsed = JSON.parse(item)
      // Rehydrate Set from array
      if (parsed.state?.unlockedUpgrades) {
        parsed.state.unlockedUpgrades = new Set(parsed.state.unlockedUpgrades)
      }
      return parsed
    } catch {
      return null
    }
  },
  setItem: (key, value) => {
    const serialized = JSON.stringify(value)
    window.localStorage.setItem(key, serialized)
  },
  removeItem: (key) => {
    window.localStorage.removeItem(key)
  }
}

const useGameStore = create<GameStateStore>()(
  persist(
    (set) => ({
      poop: 0,
      clickPower: 1,
      autoRate: 0,
      unlockedUpgrades: new Set(),
      gameStarted: false,

      incrementPoop: () => set((state) => ({
        poop: state.poop + state.clickPower
      })),

      setClickPower: (power) => set({ clickPower: power }),

      setAutoRate: (rate) => set({ autoRate: rate }),

      unlockUpgrade: (upgradeId) => set((state) => {
        const newUpgrades = new Set(state.unlockedUpgrades)
        newUpgrades.add(upgradeId)
        return { unlockedUpgrades: newUpgrades }
      }),

      resetGame: () => set({
        poop: 0,
        clickPower: 1,
        autoRate: 0,
        unlockedUpgrades: new Set(),
        gameStarted: false
      })
    }),
    {
      name: 'attack-on-toilet-state',
      storage: localStorage,
      partialize: (state) => ({
        ...state,
        unlockedUpgrades: Array.from(state.unlockedUpgrades)
      })
    }
  )
)

export { useGameStore }

import { useStore } from 'zustand'
import { useGameStore as gameStore } from '../store'

function useGameStoreHook<T>(selector: (state: ReturnType<typeof gameStore>) => T): T {
  return useStore(gameStore, selector)
}

export { useGameStoreHook }

import React from 'react'
