export { GameUI }

import React, { useState } from 'react'
import { useGameStore } from '../store'

function ToiletButton() {
  const [isClicking, setIsClicking] = useState(false)
  const incrementPoop = useGameStore((state) => state.incrementPoop)

  const handleClick = () => {
    // Trigger animation
    setIsClicking(true)
    setTimeout(() => setIsClicking(false), 150)

    // Update game state
    incrementPoop()
  }

  return (
    <button
      onClick={handleClick}
      className="relative group focus:outline-none"
      aria-label="Flush and collect poop"
    >
      {/* Glow effect */}
      <div className="absolute inset-0 rounded-full bg-purple-500/30 blur-xl transition-all duration-300 group-hover:scale-125 group-hover:bg-purple-400/40" />

      {/* Main button */}
      <div
        className={`
          relative z-10 flex items-center justify-center
          w-[120px] h-[120px] md:w-[140px] md:h-[140px]
          rounded-full bg-gradient-to-br from-purple-700 to-indigo-900
          border-4 border-purple-500/30 shadow-xl
          transition-all duration-150 ease-out
          ${isClicking ? 'scale-90' : 'hover:scale-105 hover:shadow-purple-500/20'}
        `}
      >
        <span className="text-[64px] md:text-[80px] animate-pulse-slow">
          🚽
        </span>
      </div>
    </button>
  )
}

export { ToiletButton }

import React from 'react'
import { useGameStore } from '../store'

function StatDisplay() {
  const poop = useGameStore((state) => state.poop)
  const clickPower = useGameStore((state) => state.clickPower)
  const autoRate = useGameStore((state) => state.autoRate)

  return (
    <div className="flex flex-col items-center gap-4">
      {/* Poop count */}
      <div className="relative">
        <div className="absolute inset-0 bg-yellow-500/20 blur-xl rounded-full" />
        <div className="relative z-10 text-center">
          <h2 className="text-6xl md:text-7xl font-bold text-yellow-400 drop-shadow-lg animate-bounce-pulse">
            {poop.toLocaleString()}
          </h2>
          <p className="text-yellow-300/80 text-sm mt-1">Poop Collected</p>
        </div>
      </div>

