function FloatingNumber() {
  const [floatingNumbers, setFloatingNumbers] = React.useState<FloatingNumberProps[]>([])
  const idCounter = useRef(0)
  const incrementPoop = useGameStore((state) => state.incrementPoop)

  // Handle click events to spawn floating numbers
  useEffect(() => {
    const handleGlobalClick = (e: MouseEvent) => {
      // Only spawn if clicking on the toilet button area
      const target = e.target as HTMLElement
      if (target.closest('button')) {
        const id = idCounter.current++
        const value = useGameStore.getState().clickPower

        setFloatingNumbers(prev => [
          ...prev,
          { id, value, x: e.clientX, y: e.clientY }
        ])

        // Remove after animation
        setTimeout(() => {
          setFloatingNumbers(prev => prev.filter(item => item.id !== id))
        }, 1000)
      }
    }

    window.addEventListener('click', handleGlobalClick)
    return () => window.removeEventListener('click', handleGlobalClick)
  }, [])

  return (
    <div className="fixed inset-0 pointer-events-none z-50">
      {floatingNumbers.map(number => (
        <div
