import { useEffect, useRef } from 'react'
import { useGameStore } from '../store'

interface PoopEmoji {
  id: number
  x: number
  y: number
  angle: number
  speed: number
}

interface FloatingText {
  id: number
  x: number
  y: number
  value: number
}

export function useGameLogic() {
  const { gameStarted, autoRate, clickPower } = useGameStore()
  const spawnPoopEmojis = useGameStore((state) => state.poop)
  const incrementPoop = useGameStore((state) => state.incrementPoop)

  const poopEmojisRef = useRef<PoopEmoji[]>([])
  const floatingTextRef = useRef<FloatingText[]>([])
  const idCounter = useRef(0)
  const animationFrameRef = useRef<number>()
  const autoGenerationIntervalRef = useRef<number>()

  // Handle auto-generation of poop
  useEffect(() => {
    if (gameStarted && autoRate > 0) {
      autoGenerationIntervalRef.current = window.setInterval(() => {
        for (let i = 0; i < autoRate; i++) {
          incrementPoop()
        }
      }, 1000)
    }

    return () => {
      if (autoGenerationIntervalRef.current) {
        clearInterval(autoGenerationIntervalRef.current)
      }
    }
  }, [gameStarted, autoRate, incrementPoop])

  // Handle poop emoji animation
  useEffect(() => {
    const animate = () => {
      // Update poop emojis
      poopEmojisRef.current = poopEmojisRef.current.filter(emoji => {
        const element = document.getElementById(`poop-${emoji.id}`)
        if (!element) return false

        const currentX = parseFloat(element.dataset.x || '0')
        const currentY = parseFloat(element.dataset.y || '0')
        const newX = currentX + Math.cos(emoji.angle) * emoji.speed
        const newY = currentY + Math.sin(emoji.angle) * emoji.speed
        const scale = 1 - (Math.abs(newY - window.innerHeight / 2) / window.innerHeight)

        element.style.left = `${newX}px`
        element.style.top = `${newY}px`
        element.style.transform = `scale(${Math.max(0.1, scale)})`
        element.style.opacity = Math.max(0.1, scale).toString()
        element.dataset.x = newX.toString()
        element.dataset.y = newY.toString()

        return scale > 0.1
      })

      // Update floating text
      floatingTextRef.current = floatingTextRef.current.filter(text => {
        const element = document.getElementById(`float-${text.id}`)
        if (!element) return false

        const currentY = parseFloat(element.dataset.y || '0')
        const newY = currentY - 2
        const opacity = Math.max(0, 1 - (newY - text.y) / 100)

        element.style.top = `${newY}px`
        element.style.opacity = opacity.toString()
        element.dataset.y = newY.toString()

        return opacity > 0
      })

      animationFrameRef.current = requestAnimationFrame(animate)
    }

    if (gameStarted) {
      animationFrameRef.current = requestAnimationFrame(animate)
    }

    return () => {
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current)
      }
    }
  }, [gameStarted])

  // Spawn poop emojis from random edges toward center
  const spawnPoopEmojisFromEdges = (count: number, clickX: number, clickY: number) => {
    const edgePositions = [
      { x: Math.random() * window.innerWidth, y: -50 }, // top
      { x: Math.random() * window.innerWidth, y: window.innerHeight + 50 }, // bottom
      { x: -50, y: Math.random() * window.innerHeight }, // left
      { x: window.innerWidth + 50, y: Math.random() * window.innerHeight } // right
    ]

    for (let i = 0; i < count; i++) {
      const edgePos = edgePositions[Math.floor(Math.random() * edgePositions.length)]
      const centerX = window.innerWidth / 2
      const centerY = window.innerHeight / 2
      const angle = Math.atan2(centerY - edgePos.y, centerX - edgePos.x)
      const speed = 5 + Math.random() * 5

      const emojiId = idCounter.current++
      poopEmojisRef.current.push({
        id: emojiId,
        x: edgePos.x,
        y: edgePos.y,
        angle,
        speed
      })

      // Create DOM element for emoji
      const emojiElement = document.createElement('div')
      emojiElement.id = `poop-${emojiId}`
      emojiElement.className = 'fixed text-2xl md:text-3xl z-30 pointer-events-none'
      emojiElement.style.left = `${edgePos.x}px`
      emojiElement.style.top = `${edgePos.y}px`
      emojiElement.dataset.x = edgePos.x.toString()
      emojiElement.dataset.y = edgePos.y.toString()
      emojiElement.textContent = '💩'

      document.body.appendChild(emojiElement)

      // Remove after animation
      setTimeout(() => {
        const element = document.getElementById(`poop-${emojiId}`)
        if (element) {
          element.remove()
        }
      }, 2000)
    }
  }

  // Spawn floating text
  const spawnFloatingText = (x: number, y: number, value: number) => {
    const floatId = idCounter.current++
    floatingTextRef.current.push({
      id: floatId,
      x,
      y,
      value
    })

    // Create DOM element for floating text
    const floatElement = document.createElement('div')
    floatElement.id = `float-${floatId}`
    floatElement.className = 'fixed text-xl md:text-2xl font-bold text-yellow-400 z-40 pointer-events-none'
    floatElement.style.left = `${x}px`
    floatElement.style.top = `${y}px`
    floatElement.dataset.y = y.toString()
    floatElement.textContent = `+${value}`

    document.body.appendChild(floatElement)

    // Remove after animation
    setTimeout(() => {
      const element = document.getElementById(`float-${floatId}`)
      if (element) {
        element.remove()
      }
    }, 1000)
  }

  // Handle click on toilet button
  const handleToiletClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    // Get click position relative to viewport
    const rect = e.currentTarget.getBoundingClientRect()
    const centerX = rect.left + rect.width / 2
    const centerY = rect.top + rect.height / 2

    // Calculate poop count based on click power
    const poopCount = Math.min(8, Math.floor(Math.log10(clickPower)) + 1)

    // Spawn emojis
    spawnPoopEmojisFromEdges(poopCount, centerX, centerY)

    // Spawn floating text
    spawnFloatingText(centerX, centerY - 50, clickPower)

    // Update game state
    incrementPoop()
  }

  return {
    handleToiletClick,
    gameStarted
  }
}

export default useGameLogic

